<?php
session_start();
$conn = new mysqli('localhost', 'root', '', 'agroconnect');
$conn->set_charset('utf8mb4');
require_once 'agro_helper.php';
if (!isset($_SESSION['rol']) || $_SESSION['rol'] != 'jefe') { header('Location: login.php'); exit(); }
$empresa_id = intval($_SESSION['empresa_id'] ?? 0);
$empresaNombre = 'Sin empresa asignada';
$totalTrabajadores = $totalParcelas = $totalCultivos = $tareasPendientes = $tareasIncidencia = $tareasCompletadas = 0;
$ultimasTareas = null;
if ($empresa_id > 0) {
    $st = $conn->prepare('SELECT nombre FROM empresas WHERE id=?'); $st->bind_param('i', $empresa_id); $st->execute();
    $e = $st->get_result()->fetch_assoc(); if($e){ $empresaNombre = $e['nombre']; }
    $st2 = $conn->prepare("SELECT COUNT(*) AS total FROM usuarios WHERE empresa_id=? AND rol='trabajador'"); $st2->bind_param('i', $empresa_id); $st2->execute(); $totalTrabajadores = intval($st2->get_result()->fetch_assoc()['total'] ?? 0);
    if(agro_tabla_existe($conn,'parcelas')){ $p=$conn->prepare('SELECT COUNT(*) total FROM parcelas WHERE empresa_id=?'); $p->bind_param('i',$empresa_id); $p->execute(); $totalParcelas=intval($p->get_result()->fetch_assoc()['total']??0); }
    if(agro_tabla_existe($conn,'cultivos')){ $c=$conn->prepare('SELECT COUNT(*) total FROM cultivos WHERE empresa_id=?'); $c->bind_param('i',$empresa_id); $c->execute(); $totalCultivos=intval($c->get_result()->fetch_assoc()['total']??0); }
    if(agro_tabla_existe($conn,'tareas_agricolas') && agro_columna_existe($conn,'tareas_agricolas','trabajador_id')){
        $ts=$conn->prepare("SELECT estado, COUNT(*) total FROM tareas_agricolas WHERE empresa_id=? GROUP BY estado"); $ts->bind_param('i',$empresa_id); $ts->execute(); $rs=$ts->get_result();
        while($r=$rs->fetch_assoc()){ if($r['estado']==='pendiente')$tareasPendientes=intval($r['total']); if($r['estado']==='incidencia')$tareasIncidencia=intval($r['total']); if($r['estado']==='completada')$tareasCompletadas=intval($r['total']); }
        $ut=$conn->prepare("SELECT t.titulo,t.estado,t.fecha_limite,u.nombre trabajador,p.nombre parcela FROM tareas_agricolas t LEFT JOIN usuarios u ON t.trabajador_id=u.id LEFT JOIN parcelas p ON t.parcela_id=p.id WHERE t.empresa_id=? ORDER BY t.id DESC LIMIT 5"); $ut->bind_param('i',$empresa_id); $ut->execute(); $ultimasTareas=$ut->get_result();
    }
}
?>
